const period = $('Parse Input').first().json;
const tasks = ($('Fetch Project Tasks').first().json.result || []);
const invoices = ($('Fetch Posted Invoices/Bills').first().json.result || []);
const taxLines = ($('Fetch Tax Lines').first().json.result || []);

// --- Task Completion ---
const taskByStage = {};
tasks.forEach(t => {
  const stage = t.stage_id ? t.stage_id[1] : 'Unknown';
  if (!taskByStage[stage]) taskByStage[stage] = { count: 0, tasks: [] };
  taskByStage[stage].count++;
  taskByStage[stage].tasks.push({ id: t.id, name: t.name, deadline: t.date_deadline });
});

const taskCompletion = {
  total: tasks.length,
  by_stage: taskByStage,
  completed_stages: Object.keys(taskByStage).filter(s => ['Closed', 'Compliance Closed', 'Submitted', 'Posted'].includes(s)),
  overdue: tasks.filter(t => t.date_deadline && t.date_deadline < period.date_to && !['Closed', 'Compliance Closed'].includes(t.stage_id?.[1]))
    .map(t => ({ id: t.id, name: t.name, stage: t.stage_id?.[1], deadline: t.date_deadline }))
};

// --- Invoice Summary ---
const invoiceSummary = {
  total_count: invoices.length,
  by_type: {},
  total_amount: 0,
  total_tax: 0
};

invoices.forEach(inv => {
  const type = inv.move_type;
  if (!invoiceSummary.by_type[type]) invoiceSummary.by_type[type] = { count: 0, amount: 0, tax: 0 };
  invoiceSummary.by_type[type].count++;
  invoiceSummary.by_type[type].amount += inv.amount_total || 0;
  invoiceSummary.by_type[type].tax += inv.amount_tax || 0;
  invoiceSummary.total_amount += inv.amount_total || 0;
  invoiceSummary.total_tax += inv.amount_tax || 0;
});

// --- Tax Summary ---
const taxSummary = {
  total_lines: taxLines.length,
  by_tax: {},
  vat_output: 0,
  vat_input: 0,
  ewt: 0
};

taxLines.forEach(line => {
  const taxName = line.tax_line_id ? line.tax_line_id[1] : 'Unknown';
  if (!taxSummary.by_tax[taxName]) taxSummary.by_tax[taxName] = { debit: 0, credit: 0, balance: 0 };
  taxSummary.by_tax[taxName].debit += line.debit || 0;
  taxSummary.by_tax[taxName].credit += line.credit || 0;
  taxSummary.by_tax[taxName].balance += line.balance || 0;

  const lower = taxName.toLowerCase();
  if (lower.includes('output') || lower.includes('vat out') || lower.includes('sales tax')) {
    taxSummary.vat_output += Math.abs(line.balance || 0);
  } else if (lower.includes('input') || lower.includes('vat in') || lower.includes('purchase tax')) {
    taxSummary.vat_input += Math.abs(line.balance || 0);
  } else if (lower.includes('ewt') || lower.includes('withholding') || lower.includes('creditable')) {
    taxSummary.ewt += Math.abs(line.balance || 0);
  }
});

// --- Sign-offs ---
const signOffs = {
  generated_at: new Date().toISOString(),
  generated_by: 'n8n/evidence-pack-generator',
  period: period.month,
  project_id: period.project_id,
  task_coverage: tasks.length > 0,
  invoice_coverage: invoices.length > 0,
  tax_coverage: taxLines.length > 0,
  completeness_score: [
    tasks.length > 0 ? 1 : 0,
    invoices.length > 0 ? 1 : 0,
    taxLines.length > 0 ? 1 : 0
  ].reduce((a, b) => a + b, 0) / 3 * 100
};

const evidencePack = {
  metadata: {
    version: '1.0.0',
    period: period.month,
    month_name: period.month_name,
    project_id: period.project_id,
    date_range: { from: period.date_from, to: period.date_to },
    generated_at: signOffs.generated_at
  },
  task_completion: taskCompletion,
  invoice_summary: invoiceSummary,
  tax_summary: taxSummary,
  sign_offs: signOffs
};

return { json: evidencePack };

const pack = $('Compile Evidence Pack').first().json;

return {
  json: {
    status: 'ok',
    period: pack.metadata.period,
    month_name: pack.metadata.month_name,
    project_id: pack.metadata.project_id,
    summary: {
      tasks_found: pack.task_completion.total,
      overdue_count: pack.task_completion.overdue.length,
      invoices_posted: pack.invoice_summary.total_count,
      invoice_total: pack.invoice_summary.total_amount,
      tax_lines: pack.tax_summary.total_lines,
      vat_output: pack.tax_summary.vat_output,
      vat_input: pack.tax_summary.vat_input,
      ewt: pack.tax_summary.ewt,
      completeness_score: pack.sign_offs.completeness_score
    },
    evidence_pack: pack
  }
};
